        /// <summary>
        /// Masks PII patterns like emails and SSNs in values.
        /// </summary>
        private static object MaskPii(string key, string value)
        {
            if (string.IsNullOrEmpty(value))
                return value;

            // Mask email addresses: show first 2 chars + domain
            if (key.Contains("email", StringComparison.OrdinalIgnoreCase) ||
                Regex.IsMatch(value, @"^[^@]+@[^@]+\.[^@]+$"))
            {
                return MaskEmail(value);
            }

            // Mask SSN patterns
            if (Regex.IsMatch(value, @"^\d{3}-?\d{2}-?\d{4}$"))
            {
                return "***-**-" + value[^4..];
            }

            // Mask phone numbers
            if (key.Contains("phone", StringComparison.OrdinalIgnoreCase) &&
                Regex.IsMatch(value, @"[\d\-\(\)\+\s]{7,}"))
            {
                return MaskPhone(value);
            }

            return value;
        }

        private static string MaskEmail(string email)
        {
            var parts = email.Split('@');
            if (parts.Length != 2) return "[REDACTED_EMAIL]";
            var local = parts[0];
            var masked = local.Length > 2 ? local[..2] + new string('*', local.Length - 2) : new string('*', local.Length);
            return $"{masked}@{parts[1]}";
        }

        private static string MaskPhone(string phone)
        {
            var digits = Regex.Replace(phone, @"[^\d]", "");
            if (digits.Length >= 4)
                return "***-***-" + digits[^4..];
            return "[REDACTED_PHONE]";
        }

        private static string RedactPatternsInPlainText(string text)
        {
            // Redact Bearer tokens
            text = Regex.Replace(text, @"Bearer\s+[A-Za-z0-9\-._~+/]+=*", "Bearer [REDACTED]", RegexOptions.IgnoreCase);
