        /// <summary>
        /// Sanitizes user identity claims for logging.
        /// Logs claim types but redacts sensitive claim values.
        /// </summary>
        public static Dictionary<string, string> SanitizeUserClaims(ClaimsPrincipal user)
        {
            var sanitized = new Dictionary<string, string>();
            if (user?.Identity?.IsAuthenticated != true)
            {
                sanitized["authenticated"] = "false";
                return sanitized;
            }

            sanitized["authenticated"] = "true";
            sanitized["authenticationType"] = user.Identity.AuthenticationType ?? "unknown";

            var sensitiveClaims = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "access_token", "id_token", "refresh_token", "nonce"
            };

            foreach (var claim in user.Claims)
            {
                if (sensitiveClaims.Contains(claim.Type))
                {
                    sanitized[claim.Type] = "[REDACTED]";
                }
                else if (claim.Type.Contains("email", StringComparison.OrdinalIgnoreCase))
                {
                    sanitized[claim.Type] = MaskEmail(claim.Value);
                }
                else if (claim.Type.Contains("nameidentifier", StringComparison.OrdinalIgnoreCase) ||
                         claim.Type.Contains("objectidentifier", StringComparison.OrdinalIgnoreCase) ||
                         claim.Type == "sub" || claim.Type == "oid")
                {
                    // User IDs are safe to log for correlation
                    sanitized[claim.Type] = claim.Value;
                }
                else if (claim.Type.Contains("name", StringComparison.OrdinalIgnoreCase))
                {
                    // Partially mask names
                    sanitized[claim.Type] = claim.Value.Length > 2
                        ? claim.Value[..2] + new string('*', claim.Value.Length - 2)
                        : "**";
                }
                else
                {
                    sanitized[claim.Type] = claim.Value;
                }
            }

            return sanitized;
        }

        /// <summary>
        /// Sanitizes exception details - removes connection strings and secrets from messages.
        /// </summary>
        public static string SanitizeExceptionMessage(string message)
        {
            if (string.IsNullOrEmpty(message))
                return message;

            // Redact connection strings
            message = Regex.Replace(message,
                @"(Server|Data Source|Initial Catalog|User ID|Password|Integrated Security|Trusted_Connection)[^;""']*",
                "[REDACTED_CONNECTION_INFO]",
                RegexOptions.IgnoreCase);

            // Redact tokens/keys in exception messages
            message = Regex.Replace(message, @"Bearer\s+[A-Za-z0-9\-._~+/]+=*", "Bearer [REDACTED]", RegexOptions.IgnoreCase);

            return message;
        }
