    /// <summary>
    /// Generates correlation IDs for request tracing across distributed systems.
    /// </summary>
    public static class CorrelationHelper
    {
        public static string GetOrCreateCorrelationId(HttpRequest request)
        {
            if (request.Headers.TryGetValue("X-Correlation-ID", out var correlationId) &&
                !string.IsNullOrWhiteSpace(correlationId))
            {
                return correlationId.ToString();
            }

            if (request.Headers.TryGetValue("X-Request-ID", out var requestId) &&
                !string.IsNullOrWhiteSpace(requestId))
            {
                return requestId.ToString();
            }

            return Guid.NewGuid().ToString("N");
        }
    }

