                "ContentType: {ContentType}, ContentLength: {ContentLength}, Scheme: {Scheme}, " +
                "Host: {Host}, RemoteIp: {RemoteIp}",
                correlationId,
                req.Method,
                req.Path.Value,
                req.ContentType ?? "none",
                req.ContentLength ?? 0,
                req.Scheme,
                req.Host.Value,
                req.HttpContext.Connection.RemoteIpAddress?.ToString() ?? "unknown");
        }

        private static void LogSanitizedHeaders(HttpRequest req, string correlationId, ILogger log)
        {
            var sanitizedHeaders = LogSanitizer.SanitizeHeaders(req.Headers);
            log.LogDebug(
                "Request headers (sanitized). CorrelationId: {CorrelationId}, Headers: {Headers}",
                correlationId,
                JsonConvert.SerializeObject(sanitizedHeaders, Formatting.Indented));
        }

        private static void LogSanitizedQueryParams(HttpRequest req, string correlationId, ILogger log)
        {
            if (req.Query.Any())
            {
                var sanitizedQuery = LogSanitizer.SanitizeQueryParams(req.Query);
                log.LogDebug(
                    "Query parameters (sanitized). CorrelationId: {CorrelationId}, Params: {Params}",
                    correlationId,
                    JsonConvert.SerializeObject(sanitizedQuery));
            }
        }

        private static async Task<string> ReadAndLogSanitizedBody(HttpRequest req, string correlationId, ILogger log)
        {
            req.EnableBuffering();
            string requestBody;
            using (var reader = new StreamReader(req.Body, leaveOpen: true))
            {
                requestBody = await reader.ReadToEndAsync();
                req.Body.Position = 0;
            }

            if (!string.IsNullOrWhiteSpace(requestBody))
            {
                // Enforce a max body size for logging to prevent log injection / DoS
                const int maxLogBodySize = 10_000;
                var bodyToLog = requestBody.Length > maxLogBodySize
                    ? requestBody[..maxLogBodySize] + $"... [TRUNCATED, total length: {requestBody.Length}]"
                    : requestBody;

                var sanitizedBody = LogSanitizer.SanitizeBody(bodyToLog);
                log.LogDebug(
                    "Request body (sanitized). CorrelationId: {CorrelationId}, Body: {Body}",
                    correlationId,
                    sanitizedBody);
            }
            else
            {
                log.LogDebug("Request body is empty. CorrelationId: {CorrelationId}", correlationId);
            }

            return requestBody;
        }

        private static void LogSanitizedUserContext(HttpRequest req, string correlationId, ILogger log)
        {
