        }

        private static async Task<object> ProcessRequest(string action, string requestBody, string correlationId, ILogger log)
        {
            switch (action?.ToLowerInvariant())
            {
                case "query":
                    return await ExecuteDatabaseQuery(requestBody, correlationId, log);

                case "health":
                    return await PerformHealthCheck(correlationId, log);

                default:
                    log.LogInformation(
                        "Default action processing. CorrelationId: {CorrelationId}, Action: {Action}",
                        correlationId, action ?? "null");
                    return new { message = "Request processed", action = action ?? "default" };
            }
        }

        /// <summary>
        /// Executes a database query with comprehensive but sanitized logging.
        /// Uses parameterized queries to prevent SQL injection.
        /// </summary>
        private static async Task<object> ExecuteDatabaseQuery(string requestBody, string correlationId, ILogger log)
        {
            // Connection string from secure configuration (Azure Key Vault / App Settings)
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            if (string.IsNullOrEmpty(connectionString))
            {
                log.LogError("Database connection string not configured. CorrelationId: {CorrelationId}", correlationId);
                throw new InvalidOperationException("Database configuration is missing.");
            }

            dynamic queryRequest;
            try
            {
                queryRequest = JsonConvert.DeserializeObject<dynamic>(requestBody ?? "{}");
            }
            catch (JsonException ex)
            {
                log.LogWarning("Invalid JSON in request body. CorrelationId: {CorrelationId}, Error: {Error}",
                    correlationId, ex.Message);
                throw new ArgumentException("Request body must be valid JSON.");
            }

            string userId = queryRequest?.userId;
            string searchTerm = queryRequest?.searchTerm;

            if (string.IsNullOrWhiteSpace(userId))
            {
                throw new ArgumentException("userId is required.");
            }

            // ALWAYS use parameterized queries - never concatenate user input into SQL
            const string sql = @"
                SELECT Id, DisplayName, Email, CreatedDate, LastLoginDate 
                FROM Users 
                WHERE UserId = @UserId 
                AND (@SearchTerm IS NULL OR DisplayName LIKE @SearchTerm)
                ORDER BY CreatedDate DESC
                OFFSET 0 ROWS FETCH NEXT 50 ROWS ONLY";

            var startTime = DateTime.UtcNow;

            using (var connection = new SqlConnection(connectionString))
            using (var command = new SqlCommand(sql, connection))
            {
                // Parameterized query prevents SQL injection
                command.Parameters.AddWithValue("@UserId", userId);
                command.Parameters.AddWithValue("@SearchTerm",
                    string.IsNullOrWhiteSpace(searchTerm) ? (object)DBNull.Value : $"%{searchTerm}%");
                command.CommandTimeout = 30;

                // Log the query and sanitized parameters
                var sanitizedParams = LogSanitizer.SanitizeSqlParameters(command.Parameters);
                log.LogInformation(
                    "Executing database query. CorrelationId: {CorrelationId}, Query: {Query}, " +
                    "Parameters: {Parameters}, Timeout: {Timeout}s",
                    correlationId,
                    sql,
                    JsonConvert.SerializeObject(sanitizedParams),
                    command.CommandTimeout);

                await connection.OpenAsync();
                var results = new List<Dictionary<string, object>>();

                using (var reader = await command.ExecuteReaderAsync())
                {
                    while (await reader.ReadAsync())
                    {
                        var row = new Dictionary<string, object>();
                        for (int i = 0; i < reader.FieldCount; i++)
                        {
                            row[reader.GetName(i)] = reader.IsDBNull(i) ? null : reader.GetValue(i);
                        }
                        results.Add(row);
                    }
                }

                var elapsed = DateTime.UtcNow - startTime;
                log.LogInformation(
                    "Database query completed. CorrelationId: {CorrelationId}, RowCount: {RowCount}, " +
                    "ElapsedMs: {ElapsedMs}",
                    correlationId,
                    results.Count,
                    elapsed.TotalMilliseconds);

                // Warn on slow queries
                if (elapsed.TotalMilliseconds > 2000)
                {
                    log.LogWarning(
                        "Slow query detected. CorrelationId: {CorrelationId}, ElapsedMs: {ElapsedMs}, " +
                        "Query: {Query}",
                        correlationId, elapsed.TotalMilliseconds, sql);
                }

                return new { rowCount = results.Count, results };
            }
        }

        private static async Task<object> PerformHealthCheck(string correlationId, ILogger log)
        {
            log.LogInformation("Performing health check. CorrelationId: {CorrelationId}", correlationId);

            var checks = new Dictionary<string, string>();

            // Check database connectivity
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            if (!string.IsNullOrEmpty(connectionString))
            {
                try
                {
                    using var connection = new SqlConnection(connectionString);
                    await connection.OpenAsync();
                    using var cmd = new SqlCommand("SELECT 1", connection);
                    await cmd.ExecuteScalarAsync();
                    checks["database"] = "healthy";
                }
                catch (Exception ex)
                {
                    checks["database"] = "unhealthy";
                    log.LogError(ex,
                        "Health check: database unhealthy. CorrelationId: {CorrelationId}, Error: {Error}",
                        correlationId,
                        LogSanitizer.SanitizeExceptionMessage(ex.Message));
                }
            }
            else
            {
                checks["database"] = "not_configured";
            }

            checks["function"] = "healthy";
            checks["timestamp"] = DateTime.UtcNow.ToString("O");

            log.LogInformation(
                "Health check completed. CorrelationId: {CorrelationId}, Results: {Results}",
                correlationId,
                JsonConvert.SerializeObject(checks));

            return checks;
        }

        private static void LogDatabaseException(SqlException sqlEx, string correlationId, ILogger log)
        {
            log.LogError(sqlEx,
                "Database error. CorrelationId: {CorrelationId}, ErrorNumber: {ErrorNumber}, " +
                "State: {State}, Class: {Class}, LineNumber: {LineNumber}, " +
                "Procedure: {Procedure}, Message: {Message}",
                correlationId,
                sqlEx.Number,
                sqlEx.State,
                sqlEx.Class,
                sqlEx.LineNumber,
                sqlEx.Procedure ?? "N/A",
                LogSanitizer.SanitizeExceptionMessage(sqlEx.Message));

            // Log each SQL error in the collection
            foreach (SqlError error in sqlEx.Errors)
            {
                log.LogError(
                    "SQL Error detail. CorrelationId: {CorrelationId}, Source: {Source}, " +
                    "Number: {Number}, State: {State}, Class: {Class}, " +
                    "Server: {Server}, Message: {Message}",
                    correlationId,
                    error.Source,
                    error.Number,
                    error.State,
                    error.Class,
                    "[REDACTED]", // Never log server names
                    LogSanitizer.SanitizeExceptionMessage(error.Message));
            }
        }

        /// <summary>
        /// Logs the full exception chain with sanitized messages.
        /// Captures stack traces, inner exceptions, and aggregate exceptions.
        /// </summary>
        private static void LogFullException(Exception ex, string correlationId, ILogger log)
        {
            log.LogError(ex,
                "Unhandled exception. CorrelationId: {CorrelationId}, Type: {ExceptionType}, " +
                "Message: {Message}, Source: {Source}, TargetSite: {TargetSite}",
                correlationId,
                ex.GetType().FullName,
                LogSanitizer.SanitizeExceptionMessage(ex.Message),
                ex.Source ?? "unknown",
                ex.TargetSite?.ToString() ?? "unknown");

            // Log stack trace separately for readability
            if (!string.IsNullOrEmpty(ex.StackTrace))
            {
                log.LogError(
                    "Stack trace. CorrelationId: {CorrelationId}, StackTrace: {StackTrace}",
                    correlationId,
                    ex.StackTrace);
            }

            // Walk the inner exception chain
            var innerEx = ex.InnerException;
            int depth = 1;
            while (innerEx != null && depth <= 10) // Limit depth to prevent infinite loops
            {
                log.LogError(innerEx,
                    "Inner exception (depth {Depth}). CorrelationId: {CorrelationId}, " +
                    "Type: {ExceptionType}, Message: {Message}",
                    depth,
                    correlationId,
                    innerEx.GetType().FullName,
                    LogSanitizer.SanitizeExceptionMessage(innerEx.Message));

                innerEx = innerEx.InnerException;
                depth++;
            }

            // Handle AggregateException
            if (ex is AggregateException aggEx)
            {
                var flattened = aggEx.Flatten();
                for (int i = 0; i < flattened.InnerExceptions.Count && i < 20; i++)
                {
                    var inner = flattened.InnerExceptions[i];
                    log.LogError(inner,
                        "Aggregate inner exception [{Index}]. CorrelationId: {CorrelationId}, " +
                        "Type: {ExceptionType}, Message: {Message}",
                        i,
                        correlationId,
                        inner.GetType().FullName,
                        LogSanitizer.SanitizeExceptionMessage(inner.Message));
                }
            }

            // Log exception data dictionary if present
            if (ex.Data.Count > 0)
            {
                var safeData = new Dictionary<string, string>();
                foreach (var key in ex.Data.Keys)
                {
                    var keyStr = key?.ToString() ?? "null";
                    var valStr = ex.Data[key]?.ToString() ?? "null";
                    safeData[keyStr] = LogSanitizer.SanitizeExceptionMessage(valStr);
                }

                log.LogError(
                    "Exception data. CorrelationId: {CorrelationId}, Data: {Data}",
                    correlationId,
                    JsonConvert.SerializeObject(safeData));
            }
        }
    }
}